<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Models\HrPerformanceCycle; use App\Modules\Hr\Performance\Models\HrPerformanceGoal; use App\Modules\Hr\Personnel\Models\HrEmployee;
class CreatePerformanceGoalAction { public function __construct(private HrAuditService $audit){} public function execute(HrPerformanceCycle $cycle,HrEmployee $employee,array $data):HrPerformanceGoal{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.performance.manage_goals'),403);abort_unless($cycle->legal_entity_id===$tenant&&$employee->legal_entity_id===$tenant,404);$weight=round((float)($data['weight']??0),2);$target=(float)($data['target_value']??0);$type=(string)($data['type']??'kpi');abort_if(blank($data['title']??null)||blank($data['metric_unit']??null)||$weight<=0||$weight>100,422);$total=(float)HrPerformanceGoal::withoutGlobalScope('tenant')->where('cycle_id',$cycle->id)->where('employee_id',$employee->id)->where('status','active')->sum('weight');abort_if($total+$weight>100.001,422,'Çalışanın hedef ağırlıkları 100 değerini aşamaz.');$goal=HrPerformanceGoal::create(['legal_entity_id'=>$tenant,'cycle_id'=>$cycle->id,'employee_id'=>$employee->id,'type'=>in_array($type,['kpi','okr'],true)?$type:'kpi','title'=>trim($data['title']),'description'=>$data['description']??null,'metric_unit'=>trim($data['metric_unit']),'baseline_value'=>$data['baseline_value']??0,'target_value'=>$target,'current_value'=>$data['current_value']??0,'weight'=>$weight,'status'=>'active','created_by'=>auth()->id()]);$this->audit->log('performance_goal_created',$goal);return $goal;} }
